import {
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
} from '@/components/ui/card';
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from '@/components/ui/table';
import type { Service } from '@/lib/types';
import { ReactNode } from 'react';

interface PricingTableProps {
    title: string;
    description: string;
    services: Service[];
    subheading?: string;
    footerContent?: ReactNode;
}

export function PricingTable({ title, description, services, subheading, footerContent }: PricingTableProps) {
  const hasHirePurchase = services.some(s => 'hirePrice' in s || 'purchasePrice' in s);

  const showHeader = title || description || subheading;

  return (
    <Card>
      {showHeader && (
        <CardHeader>
          {title && <CardTitle>{title}</CardTitle>}
          {description && <CardDescription>{description}</CardDescription>}
          {subheading && <h2 className="text-2xl font-headline font-bold text-foreground pt-4">{subheading}</h2>}
        </CardHeader>
      )}
      <CardContent className={footerContent ? 'pb-0' : ''}>
        <Table>
          <TableHeader>
            <TableRow>
              <TableHead>Service</TableHead>
              <TableHead>Description</TableHead>
              {hasHirePurchase ? (
                <>
                  <TableHead className="text-right">Hire Price</TableHead>
                  <TableHead className="text-right">Purchase Price</TableHead>
                </>
              ) : (
                <TableHead className="text-right">Price</TableHead>
              )}
            </TableRow>
          </TableHeader>
          <TableBody>
            {services.map((service) => (
              <TableRow key={service.id}>
                <TableCell className="font-medium">{service.name}</TableCell>
                <TableCell className="text-muted-foreground">
                    {'description' in service ? service.description : ''}
                </TableCell>
                {hasHirePurchase ? (
                    <>
                        <TableCell className="text-right">
                            <span className="font-semibold">{'hirePrice' in service && service.hirePrice ? service.hirePrice : ''}</span>
                        </TableCell>
                         <TableCell className="text-right">
                            <span className="font-semibold">{'purchasePrice' in service && service.purchasePrice ? service.purchasePrice : ''}</span>
                        </TableCell>
                    </>
                ): (
                    <TableCell className="text-right">
                        <span className="font-semibold">{'price' in service ? service.price : ''}</span>
                        {'unit' in service && service.unit && <span className="text-sm text-muted-foreground">/{service.unit}</span>}
                    </TableCell>
                )}
              </TableRow>
            ))}
          </TableBody>
        </Table>
      </CardContent>
      {footerContent}
    </Card>
  );
}
